## 3. Security & Verification (`src/services/pubsubVerifier.js`)

```javascript
const { OAuth2Client } = require('google-auth-library');
const logger = require('../config/logger');

const client = new OAuth2Client();

class PubSubVerifier {
  constructor() {
    this.audience = process.env.GOOGLE_CLOUD_PROJECT_ID;
  }

  async verifyToken(token) {
    try {
      const ticket = await client.verifyIdToken({
        idToken: token,
        audience: this.audience,
      });

      const payload = ticket.getPayload();

      // Verify email matches service account or expected sender
      if (!payload.email.endsWith('@gcp-sa-pubsub.iam.gserviceaccount.com') && 
          !payload.email_verified) {
        throw new Error('Invalid token issuer');
      }

      return payload;
    } catch (error) {
      logger.error('Token verification failed:', error);
      throw new Error('Unauthorized');
    }
  }
}

module.exports = new PubSubVerifier();
```

## 4. Gmail Service (`src/services/gmailService.js`)

```javascript
const { google } = require('googleapis');
const logger = require('../config/logger');
const retry = require('../utils/retry');

class GmailService {
  constructor() {
    this.auth = new google.auth.OAuth2(
      process.env.GMAIL_CLIENT_ID,
      process.env.GMAIL_CLIENT_SECRET,
      process.env.GMAIL_REDIRECT_URI
    );

    this.auth.setCredentials({
      refresh_token: process.env.GMAIL_REFRESH_TOKEN,
    });

    this.gmail = google.gmail({ version: 'v1', auth: this.auth });
  }

  async getMessage(messageId) {
    return retry(async () => {
      const response = await this.gmail.users.messages.get({
        userId: 'me',
        id: messageId,
        format: 'full',
      });
      return response.data;
    }, { retries: 3, delay: 1000 });
  }

  async listHistory(historyId) {
    return retry(async () => {
      const response = await this.gmail.users.history.list({
        userId: 'me',
        startHistoryId: historyId,
        labelId: 'INBOX',
        maxResults: 100,
      });
      return response.data.history || [];
    }, { retries: 3, delay: 1000 });
  }

  async watchInbox() {
    const response = await this.gmail.users.watch({
      userId: 'me',
      requestBody: {
        labelIds: ['INBOX'],
        topicName: `projects/${process.env.GOOGLE_CLOUD_PROJECT_ID}/topics/${process.env.PUBSUB_TOPIC}`,
      },
    });
    logger.info('Watch established', { historyId: response.data.historyId });
    return response.data;
  }

  parseMessage(message) {
    const headers = message.payload.headers.reduce((acc, header) => {
      acc[header.name.toLowerCase()] = header.value;
      return acc;
    }, {});

    const extractBody = (parts) => {
      let body = '';
      let htmlBody = '';

      if (!parts) return { body, htmlBody };

      for (const part of parts) {
        if (part.mimeType === 'text/plain' && part.body?.data) {
          body += Buffer.from(part.body.data, 'base64').toString('utf8');
        } else if (part.mimeType === 'text/html' && part.body?.data) {
          htmlBody += Buffer.from(part.body.data, 'base64').toString('utf8');
        } else if (part.parts) {
          const nested = extractBody(part.parts);
          body += nested.body;
          htmlBody += nested.htmlBody;
        }
      }
      return { body, htmlBody };
    };

    const { body, htmlBody } = extractBody(message.payload.parts || [message.payload]);

    return {
      messageId: message.id,
      threadId: message.threadId,
      from: headers.from,
      to: headers.to ? headers.to.split(',').map(e => e.trim()) : [],
      cc: headers.cc ? headers.cc.split(',').map(e => e.trim()) : [],
      bcc: headers.bcc ? headers.bcc.split(',').map(e => e.trim()) : [],
      subject: headers.subject,
      body: body || null,
      htmlBody: htmlBody || null,
      receivedAt: new Date(parseInt(message.internalDate)),
      labels: message.labelIds || [],
      rawPayload: message,
    };
  }
}

module.exports = new GmailService();
```

## 5. Email Service (`src/services/emailService.js`)

```javascript
const { prisma } = require('../config/database');
const redis = require('../config/redis');
const logger = require('../config/logger');

class EmailService {
  constructor() {
    this.DEDUP_TTL = 86400; // 24 hours
  }

  async storeEmail(emailData) {
    const dedupKey = `email:${emailData.messageId}`;

    // Idempotency check via Redis
    const exists = await redis.get(dedupKey);
    if (exists) {
      logger.info('Duplicate email ignored', { messageId: emailData.messageId });
      return { status: 'duplicate', data: null };
    }

    try {
      // Atomic upsert with transaction
      const email = await prisma.$transaction(async (tx) => {
        const existing = await tx.email.findUnique({
          where: { messageId: emailData.messageId },
        });

        if (existing) {
          return existing;
        }

        const created = await tx.email.create({
          data: {
            messageId: emailData.messageId,
            threadId: emailData.threadId,
            from: emailData.from,
            to: emailData.to,
            cc: emailData.cc,
            bcc: emailData.bcc,
            subject: emailData.subject,
            body: emailData.body,
            htmlBody: emailData.htmlBody,
            receivedAt: emailData.receivedAt,
            labels: emailData.labels,
            rawPayload: emailData.rawPayload,
            processed: false,
          },
        });

        return created;
      }, {
        isolationLevel: 'Serializable',
        maxWait: 5000,
        timeout: 10000,
      });

      // Set deduplication key
      await redis.setex(dedupKey, this.DEDUP_TTL, '1');

      logger.info('Email stored successfully', { 
        messageId: emailData.messageId,
        id: email.id,
        latency: Date.now() - emailData.receivedAt.getTime()
      });

      return { status: 'created', data: email };
    } catch (error) {
      logger.error('Failed to store email', { 
        messageId: emailData.messageId, 
        error: error.message 
      });
      throw error;
    }
  }

  async verifyStorage(messageId) {
    const startTime = Date.now();
    const maxWait = 5000;

    while (Date.now() - startTime < maxWait) {
      const email = await prisma.email.findUnique({
        where: { messageId },
        select: { id: true, createdAt: true }
      });

      if (email) {
        return { found: true, latency: Date.now() - startTime, email };
      }

      await new Promise(resolve => setTimeout(resolve, 50));
    }

    return { found: false, latency: Date.now() - startTime };
  }

  async getUnprocessed(limit = 100) {
    return prisma.email.findMany({
      where: { 
        processed: false,
        processingAttempts: { lt: 3 }
      },
      orderBy: { receivedAt: 'asc' },
      take: limit,
    });
  }

  async markProcessed(id, error = null) {
    const update = error 
      ? { processingAttempts: { increment: 1 }, lastError: error }
      : { processed: true, lastError: null };

    return prisma.email.update({
      where: { id },
      data: update,
    });
  }
}

module.exports = new EmailService();
```

